const Q_COMMERCE_2009=[{"id": "objective>Commerce>2009>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The central focus of commercial activities is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pricing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">advertising </div>", "<div style=\"font-family:Cambria;font-size:17px;\">trading </div>", "<div style=\"font-family:Cambria;font-size:17px;\">marketing </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Trading is the buying and selling of goods and services. It is the process of exchanging value for value. Trading is the foundation of all commercial activities. <br/>  <br/> Pricing, advertising, and marketing are all important aspects of commercial activities, but they are all secondary to trading. Pricing is the process of setting prices for goods and services. Advertising is the process of promoting goods and services to potential customers. Marketing is the process of creating and delivering value to customers.</div>", "topic": "ELEMENT OF MARKETING : THE MARKETING CONCEPT"}, {"id": "objective>Commerce>2009>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An aid to trade associated with communication is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">banking </div>", "<div style=\"font-family:Cambria;font-size:17px;\">transportation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">warehousing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">insurance</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Communication was tied closely to transportation as, in the absence of electronic communications, it depended on the speed and efficiency of transportation. Messages had to be carried, orally or in writing, from one place to another, and most traveled in the same vehicles as passengers and merchandise.</div>", "topic": "AIDS TO TRADE: COMMUNICATION : TYPES"}, {"id": "objective>Commerce>2009>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The service of textile worker are an example of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">extractive activity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">commercial activity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">manufacturing </div>", "<div style=\"font-family:Cambria;font-size:17px;\">construction </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Manufacturing occupation is concerned with the activities of those who engage in processing and turning raw materials produced in the primary industry into finished products.</div>", "topic": "OCCUPATION : TYPES OF OCCUPATION"}, {"id": "objective>Commerce>2009>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Resources harnessed in certain proportion to create goods and services are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">factors of production </div>", "<div style=\"font-family:Cambria;font-size:17px;\">technology and labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">land and entrepreneur </div>", "<div style=\"font-family:Cambria;font-size:17px;\">raw materials</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Factors of production, resources, or inputs are what is used in the production process in order to produce output—that is, finished goods. Factors of production are the resources of land, labour, capital and enterprise used to produce goods and services.</div>", "topic": "PRODUCTION : FACTORS OF PRODUCTION"}, {"id": "objective>Commerce>2009>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Primary production is associated with </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">banking </div>", "<div style=\"font-family:Cambria;font-size:17px;\">manufacturing </div>", "<div style=\"font-family:Cambria;font-size:17px;\">agriculture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">construction </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The primary sector of the economy is the sector of an economy making direct use of natural resources. This includes agriculture, forestry, fishing and mining. In contrast, the secondary sector produces manufactured goods, and the tertiary sector produces services.</div>", "topic": "OCCUPATION : MEANING & IMPORTANCE"}, {"id": "objective>Commerce>2009>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major components of modern retailing include </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">branding, doorstep selling and customer stimulation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">branding, sales, promotion and mail order </div>", "<div style=\"font-family:Cambria;font-size:17px;\">chain stores, customer stimulation and door step selling</div>", "<div style=\"font-family:Cambria;font-size:17px;\">branding, supermarkets and after-sales service </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">MODERN TRENDS IN RETAILING <br/> -   Branding. <br/> -    Self-services. <br/> -   After sales services. <br/> -   Pre-packaging. <br/> -   Vending machine</div>", "topic": "TRADE (1) : HOME TRADE: RETAIL TRADE"}, {"id": "objective>Commerce>2009>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A chain store usually combines the features of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">multiple shops and departmental stores </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hypermarkets and stalls</div>", "<div style=\"font-family:Cambria;font-size:17px;\">multiple shop and hypermarkets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mail order business and multiple shops </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Chain store(s) or retail chain are retail outlets that share a brand and central management, and usually have standardized business methods and practices.</div>", "topic": "TRADE (1) : HOME TRADE: RETAIL TRADE"}, {"id": "objective>Commerce>2009>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the aims of marketing is to ......</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">forecast prices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce prices of goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">promote sales</div>", "<div style=\"font-family:Cambria;font-size:17px;\">analyse sales periodically</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">marketing is the activity, set of institutions, and processes for creating, communicating, delivering, and exchanging offerings that have value for customers, clients, partners, and society at large. The Aim of Marketing Is to Make Selling Unnecessary.</div>", "topic": "ELEMENT OF MARKETING : THE MARKETING CONCEPT"}, {"id": "objective>Commerce>2009>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An artificial barrier to international trade is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">political unrest </div>", "<div style=\"font-family:Cambria;font-size:17px;\">culture of the people </div>", "<div style=\"font-family:Cambria;font-size:17px;\">unit of measurement </div>", "<div style=\"font-family:Cambria;font-size:17px;\">custom duties </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Customs Duty is a tariff or tax imposed on goods when transported across international borders. The purpose of Customs Duty is to protect each country's economy, residents, jobs, environment, etc., by controlling the flow of goods, especially restrictive and prohibited goods, into and out of the country.</div>", "topic": "TRADE ( 2) : CUSTOMS, EXCISE, PORTS AUTHORITY ETC."}, {"id": "objective>Commerce>2009>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most commonly used commercial documents are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">order notes, debit notes, invoices and quotations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">letter of inquiry, consignment notes, receipt and invoices </div>", "<div style=\"font-family:Cambria;font-size:17px;\">credit notes, statement of accounts, dispatch order and bills </div>", "<div style=\"font-family:Cambria;font-size:17px;\">balance sheet, receipt, invoice and manifest</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">These documents are used in a variety of commercial transactions, including sales, purchases, and consignments. <br/>  <br/> Letter of inquiry: A letter of inquiry is a document that is used to request information about a product or service. It is typically used by businesses that are considering buying or selling goods or services. <br/>  <br/> Consignment note: A consignment note is a document that is used to track the movement of goods that are being consigned from one party to another. A consignment note typically includes information about the goods being consigned, the parties involved, and the terms of the consignment agreement. <br/>  <br/> Receipt: A receipt is a document that is used to acknowledge the receipt of goods or services. A receipt typically includes information about the goods or services received, the date of receipt, and the amount paid. <br/>  <br/> Invoice: An invoice is a document that is used to bill a customer for goods or services that have been provided. An invoice typically includes information about the goods or services being billed, the quantity, the price, and the terms of payment. <br/>  <br/> Other commonly used commercial documents include: <br/>  <br/> Order note: A document that is used to place an order for goods or services. <br/> Debit note: A document that is used to issue a credit to a customer's account. <br/> Credit note: A document that is used to issue a debit to a customer's account. <br/> Statement of account: A document that is used to summarize a customer's account activity over a period of time. <br/> Dispatch order: A document that is used to authorize the shipment of goods. <br/> Bill of lading: A document that is used to track the movement of goods and to provide evidence of ownership of goods.</div>", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING"}, {"id": "objective>Commerce>2009>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The term <strong>free on board</strong> means that the price includes </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cost and insurance only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cost and freight only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">freight and insurance only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cost , insurance and freight</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The costs associated with FOB include transportation of goods to the port, loading of goods, marine freight, insurance, unloading of goods at the destination port and transportation cost up to the final destination. </div>", "topic": "TRADE ( 2) : DOCMENT USED IN INTERNATION TRADE"}, {"id": "objective>Commerce>2009>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a buyer is given 12.5% discount on ₦50,000 worth of goods, how much will he repay?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦56,250</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦43,750</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦43,250</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦6,250</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If a buyer is given a 12.5% discount on ₦50,000 worth of goods, the discount amount will be 12.5/100 * 50,000 = ₦6,250. Therefore, the amount the buyer will repay is 50,000 - 6,250 = ₦43,750.</div>", "topic": "FINANCING BUSINESS : PROFIT"}, {"id": "objective>Commerce>2009>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A cheque which a bank draws on its own funds is a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bank draft </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cashier's cheque </div>", "<div style=\"font-family:Cambria;font-size:17px;\">bank cheque </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cross cheque </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A cashier's cheque is a cheque guaranteed by a bank, drawn on the bank's own funds and signed by a cashier. Cashier's checks are treated as guaranteed funds because the bank, rather than the purchaser, is responsible for paying the amount. They are commonly required for real estate and brokerage transactions.</div>", "topic": "AIDS TO TRADE: BANKING : TYPES OF BANK"}, {"id": "objective>Commerce>2009>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Bill board and posters are forms of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">electronic media</div>", "<div style=\"font-family:Cambria;font-size:17px;\">print media</div>", "<div style=\"font-family:Cambria;font-size:17px;\">outdoor media</div>", "<div style=\"font-family:Cambria;font-size:17px;\">window display media</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Outdoor media, and out-of-home media, is advertising experienced outside of the home.This includes billboards, wall scapes, and posters</div>", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA"}, {"id": "objective>Commerce>2009>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A collective term for advertising, personal selling and publicity is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">exhibition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">promotion </div>", "<div style=\"font-family:Cambria;font-size:17px;\">trade fair</div>", "<div style=\"font-family:Cambria;font-size:17px;\">merchandizing </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Promotion is also known as COMMUNICATION. It deals with how business enterprises should inform consumer about the goods. The forms of promotion are: Advertising, Personal selling,Sales promotion,Publicity</div>", "topic": "ELEMENT OF MARKETING : MARKETING MIX"}, {"id": "objective>Commerce>2009>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Central Bank differs from commercial banks because it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">renders service to customers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carries out foreign exchange transaction </div>", "<div style=\"font-family:Cambria;font-size:17px;\">issues currencies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">discount bills</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The functions of the CBN are: bankers to the government, lender of last resort, clearing house, issuance of currencies etc. The significant difference between the two is that the central bank is the apex body running the whole banking system. Whereas, a commercial bank is just a constituent unit of the banking system which operates to facilitate exchange and make profits. </div>", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLEGES"}, {"id": "objective>Commerce>2009>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the facilities enjoyed by a current account holder is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a dividend</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a bonus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an overdraft </div>", "<div style=\"font-family:Cambria;font-size:17px;\">interest on deposit </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An overdraft occurs when the money is withdrawn in excess of what is on the current account. In this situation, the account is said to be overdrawn.</div>", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLEGES"}, {"id": "objective>Commerce>2009>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which of the following will the number of words used determine the cost of the message sent? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">telephone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Telegram </div>", "<div style=\"font-family:Cambria;font-size:17px;\">E-mail</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Telex </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A telegram is a communication sent over a telegraph. Typically, a telegraph operator receives the communication, and then writes it out for the recipient. Telegrams can also be transmitted over the phone.</div>", "topic": "AIDS TO TRADE: COMMUNICATION : PROCESS & PROCEDURE"}, {"id": "objective>Commerce>2009>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The transmission of telephone services from one country to another is facilitated by  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">communication satellite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">international facility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Interconnectivity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">internet services </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A communications satellite is an artificial satellite that relays and amplifies radio telecommunication signals via a transponder; it creates a communication channel between a source transmitter and a receiver at different locations on Earth. Communications satellites are used for television, telephone, radio, internet, and military applications.</div>", "topic": "AIDS TO TRADE: COMMUNICATION : PROCESS & PROCEDURE"}, {"id": "objective>Commerce>2009>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The principle of insurance which entitles an insurance company to take any advantage due to insured after indemnity is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">contribution </div>", "<div style=\"font-family:Cambria;font-size:17px;\">subrogation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">proximate cause </div>", "<div style=\"font-family:Cambria;font-size:17px;\">utmost good faith </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Subrogation is the act of one party claiming the legal rights of another that it has reimbursed for losses.</div>", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES"}, {"id": "objective>Commerce>2009>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A risk that can be estimated and calculated to be compensated is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a delivery risk </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an insurable risk </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a credit risk </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a systematic risk </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">insurable risks are risk that can be calculated, collected and estimated e.g. motor, life, marine insurance </div>", "topic": "AIDS TO TRADE: INSURANCE : TERMS"}, {"id": "objective>Commerce>2009>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important reason for the existence of insurance business is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">prevent the occurrence of any loss</div>", "<div style=\"font-family:Cambria;font-size:17px;\">spread losses to all covered participant </div>", "<div style=\"font-family:Cambria;font-size:17px;\">provide for the replacement of facility </div>", "<div style=\"font-family:Cambria;font-size:17px;\">encourage individual to save </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">-  It motivates workers. <br/> -   As a means of saving. <br/> -   It facilitates international trade. <br/> -   It creates employment opportunities. <br/> -   As a collateral security. <br/> -  To reduce risks. <br/> </div>", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES"}, {"id": "objective>Commerce>2009>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One major advantage of transportation to a business is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">extend the firm's market coverage </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ensure that goods are produced faster</div>", "<div style=\"font-family:Cambria;font-size:17px;\">procure raw materials cheaply </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ensure the quality of products </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Transportation helps the businesses in doing large scale production of their products by supplying each and everything very conveniently without any interruption. It makes it possible for the business to manufacture and sell their product at a cheaper cost and face the stiff and tough competition in the market.</div>", "topic": "AIDS TO TRADE: TRANSPORTATION : ADVANTAGES & DISADVANTAGES OF TRANSPORTATION"}, {"id": "objective>Commerce>2009>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Warehousing is important to manufacturer because it helps to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">improve the quality of goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">produce goods in advance </div>", "<div style=\"font-family:Cambria;font-size:17px;\">meet the demand of customers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">determine input requirements</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Warehousing is important to manufacturers because it allows them to store produced goods until they are demanded by customers. This ensures that there is a steady supply of goods to meet customer demand. Therefore, the option 'meet the demand of customers' is the correct answer.</div>", "topic": "AIDS TO TRADE: WAREHOUSING: : ADVANTAGES & DISADVANTAGES OF WAREHOUSING"}, {"id": "objective>Commerce>2009>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the major problems of a sole proprietor is sourcing for </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">raw materials</div>", "<div style=\"font-family:Cambria;font-size:17px;\">labour </div>", "<div style=\"font-family:Cambria;font-size:17px;\">food</div>", "<div style=\"font-family:Cambria;font-size:17px;\">funds</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The disadvantages of sole proprietorship are: <br/> - problem of continuity <br/> - inadequate capital <br/> - bears all risks alone <br/> - has unlimited liability <br/> - is not a separate legal entity <br/> - lacks specialisation</div>", "topic": "BUSINESS UNIT: SOLE PROPRIETORSHIP : ADVANATAGES & DISADVANTAGES"}, {"id": "objective>Commerce>2009>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a public limited liability company, planning is carried out by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">chairman of the board </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the board of directors </div>", "<div style=\"font-family:Cambria;font-size:17px;\">shareholders </div>", "<div style=\"font-family:Cambria;font-size:17px;\">employees </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A board of directors is a body of elected or appointed members who jointly oversee the activities of a company or organization.</div>", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : FEATURES AND IMPORTANCE"}, {"id": "objective>Commerce>2009>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Partnerships are most effective where </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the partners are family friends</div>", "<div style=\"font-family:Cambria;font-size:17px;\">professionals are involved </div>", "<div style=\"font-family:Cambria;font-size:17px;\">members can easily raise enough capital </div>", "<div style=\"font-family:Cambria;font-size:17px;\">government regulation are favourable </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The key elements where partnerships can benefit an organisation are, like anything in business, improving the bottom line, whether its financial or otherwise, increasing sales and enhancing reputation. Those benefits can be reaped through: Knowledge sharing; sharing of practises, skill sets and expertise across industry/destination/association.</div>", "topic": "BUSINESS UNIT: PARTNERSHIP : ADVANTAGES AND DISADVANTAGES"}, {"id": "objective>Commerce>2009>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The type of partnership in which all partners are jointly liable in bearing risk is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">limited partnership </div>", "<div style=\"font-family:Cambria;font-size:17px;\">partnership-at-will</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ordinary partnership </div>", "<div style=\"font-family:Cambria;font-size:17px;\">industrial partnership </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is the ordinary partnership. Here, each business partner (or partners) personally share responsibility for the business. Profits are shared between the partners. Each partner pays tax on their share of the profits.</div>", "topic": "BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES"}, {"id": "objective>Commerce>2009>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The financial instrument that entitles the holder to receive dividend and capital gains is a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">share</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bond</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bill of exchange </div>", "<div style=\"font-family:Cambria;font-size:17px;\">treasury bill </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A share is an equity instrument representing a fraction of the capital of the company that issued it. This type of security entitles the holder to participate in shareholders' meetings, to be informed of the company's progress and to receive dividends. A share is not redeemable and as such does not have an expiry date.</div>", "topic": "STOCK EXCHANGE : TYPES OF SECURITIES"}, {"id": "objective>Commerce>2009>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The circulating capital of a business-enterprise is classified into </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cash, work-in-progress and debtors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cash, vehicles, land and buildings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debtors,stock of raw materials,fittings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pre-payments,debtors and equipment </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">\"Circulating capital means current assets of a company that are changed in the ordinary course of business from one form to another, as for example, from cash to inventories, inventories to receivables, receivables into cash.\"</div>", "topic": "FINANCING BUSINESS : TYPES OF CAPITAL"}, {"id": "objective>Commerce>2009>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the information below to answer this question  <br/>  Ojo's balance Sheet as at 31st December, 2006 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> ₦</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> ₦ <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Capital</td><td style=\"border:1px solid black;text-align:center;\"> 10 000</td><td style=\"border:1px solid black;text-align:center;\">Land and building</td><td style=\"border:1px solid black;text-align:center;\"> 12 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Drawings</td><td style=\"border:1px solid black;text-align:center;\"> 600</td><td style=\"border:1px solid black;text-align:center;\"> Fittings</td><td style=\"border:1px solid black;text-align:center;\"> 850 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> 9 400</td><td style=\"border:1px solid black;text-align:center;\"> Motor vans</td><td style=\"border:1px solid black;text-align:center;\"> 1 600 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Profit</td><td style=\"border:1px solid black;text-align:center;\"> 6 200</td><td style=\"border:1px solid black;text-align:center;\"> Cash</td><td style=\"border:1px solid black;text-align:center;\"> 2 150 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> 15 600</td><td style=\"border:1px solid black;text-align:center;\"> prepayments</td><td style=\"border:1px solid black;text-align:center;\"> 700 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Creditors</td><td style=\"border:1px solid black;text-align:center;\"> 1 800</td><td style=\"border:1px solid black;text-align:center;\"> debtors</td><td style=\"border:1px solid black;text-align:center;\"> 100 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> 17 400</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> 17 400</td></tr></table></div> <br/>  <br/> 10% is charged on depreciation of fixed assets <br/>  <br/> Determine the value of Ojo's fixed assets</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦14,450</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦13,450</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦13,005</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦12,005</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The fixed assets in Ojo's balance sheet are Land and building, Fittings, and Motor vans. Their total value is : <br/> = ₦12,000 + ₦850 + ₦1,600  <br/> = ₦14,450.  <br/>  <br/> <strong>NOTE</strong> <br/> Depreciation is not considered in this calculation because the question asks for the value of the fixed assets, not their net book value after depreciation.</div>", "topic": "FINANCING BUSINESS : TURNOVER"}, {"id": "objective>Commerce>2009>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the information below to answer this question  <br/>  Ojo's balance Sheet as at 31st December, 2006 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> ₦</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> ₦ <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Capital</td><td style=\"border:1px solid black;text-align:center;\"> 10 000</td><td style=\"border:1px solid black;text-align:center;\">Land and building</td><td style=\"border:1px solid black;text-align:center;\"> 12 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Drawings</td><td style=\"border:1px solid black;text-align:center;\"> 600</td><td style=\"border:1px solid black;text-align:center;\"> Fittings</td><td style=\"border:1px solid black;text-align:center;\"> 850 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> 9 400</td><td style=\"border:1px solid black;text-align:center;\"> Motor vans</td><td style=\"border:1px solid black;text-align:center;\"> 1 600 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Profit</td><td style=\"border:1px solid black;text-align:center;\"> 6 200</td><td style=\"border:1px solid black;text-align:center;\"> Cash</td><td style=\"border:1px solid black;text-align:center;\"> 2 150 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> 15 600</td><td style=\"border:1px solid black;text-align:center;\"> prepayments</td><td style=\"border:1px solid black;text-align:center;\"> 700 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Creditors</td><td style=\"border:1px solid black;text-align:center;\"> 1 800</td><td style=\"border:1px solid black;text-align:center;\"> debtors</td><td style=\"border:1px solid black;text-align:center;\"> 100 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> 17 400</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> 17 400</td></tr></table></div> <br/>  <br/> 10% is charged on depreciation of fixed assets  <br/> What is Ojo's working capital?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦2,150</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦1,950</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦1,800</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦1,150</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Working capital = current assets - current liabilities  <br/>       = ₦(2,150 + 700 + 100 - 1,800)  <br/>           = ₦(2,950 - 1,800)  <br/>                   = ₦1,150</div>", "topic": "FINANCING BUSINESS : TURNOVER"}, {"id": "objective>Commerce>2009>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a firm has turn over of ₦50,000 and the cost of goods sold is ₦40,000, what is the percentage of gross profit on sale?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">30.5%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20.5%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20.0%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10.0% </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gross profit = Selling price - Cost price ( cost of goods sold) <br/>                        50,000 - 40,000 = 10,000 <br/> Therefore, Gross profit on sales = GP/Sales x 100 <br/>                                            10,000/ 50,000  x 100 <br/>                                                   = 20%</div>", "topic": "FINANCING BUSINESS : PROFIT"}, {"id": "objective>Commerce>2009>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A body established to protect the interest of members against the exploitation of retail traders and manufacturers is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">wholesaler's association</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumer's association</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government agency </div>", "<div style=\"font-family:Cambria;font-size:17px;\">workers union </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A consumer organisation/association is a membership-based non-governmental non-profit body created to promote the interests of consumers of goods and services, by disseminating information and lobbying for laws to protect consumers against producers or sellers, who may usually be better organised or have more resources.</div>", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS"}, {"id": "objective>Commerce>2009>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Manufacturers' Association of Nigeria is an example of a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">labour union </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pressure group</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conglomerate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cartel </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Manufacturers Association of Nigeria also known as MAN is a trade group headquartered in Lagos. The group act as a platform that manufacturers use to influence economic, industrial, labour and social policy within Nigeria. <br/>  <br/> Pressure group is a group that tries to influence public policy in the interest of a particular cause.</div>", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS"}, {"id": "objective>Commerce>2009>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The characteristic which ensures that money is free from forgery is its</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">legality</div>", "<div style=\"font-family:Cambria;font-size:17px;\">durability </div>", "<div style=\"font-family:Cambria;font-size:17px;\">recognition </div>", "<div style=\"font-family:Cambria;font-size:17px;\">credibility </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The characteristic of money that ensures it is free from forgery is its legality. This means that money is issued by a government authority, such as a central bank, and is recognized as legal tender. This makes it difficult to forge, as doing so is a criminal offense. The other options, durability, recognition, and credibility, are also important characteristics of money, but they do not specifically ensure that money is free from forgery.</div>", "topic": "MONEY : QUALITIES OF MONEY"}, {"id": "objective>Commerce>2009>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major dealers on stock market are the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">agents</div>", "<div style=\"font-family:Cambria;font-size:17px;\">jobbers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">investors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">brokers</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The dealers in the shares and stock are known as jobbers. Members of the public buy shares from jobber through brokers who serves as agent.</div>", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS"}, {"id": "objective>Commerce>2009>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The daily official publications of the Nigerian Stock Exchange give detailed information on the  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">changes in the official rules set by the market </div>", "<div style=\"font-family:Cambria;font-size:17px;\">method of transactions agreed upon by members </div>", "<div style=\"font-family:Cambria;font-size:17px;\">participation of members in a day</div>", "<div style=\"font-family:Cambria;font-size:17px;\">changes in the price securities </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The daily official publications of the Nigerian Stock Exchange give detailed information on the changes in the price securities. This includes information about the opening, closing, highest, and lowest prices of securities, as well as the volume of securities that were traded.</div>", "topic": "STOCK EXCHANGE : PROCEDURES OF TRANSACTIONS"}, {"id": "objective>Commerce>2009>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The function which ensures that set objectives are attained by the organization is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">planning</div>", "<div style=\"font-family:Cambria;font-size:17px;\">directing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">staffing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">controlling </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">the meaning of controlling function can be defined as ensuring that activities in an organization are performed as per the plans. Controlling also ensures that an organization's resources are being used effectively & efficiently for the achievement of predetermined goals. Controlling is a goal-oriented function.</div>", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : PRINCIPLE"}, {"id": "objective>Commerce>2009>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An organization structure that is military in nature is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">line structure </div>", "<div style=\"font-family:Cambria;font-size:17px;\">staff structure </div>", "<div style=\"font-family:Cambria;font-size:17px;\">line and staff structure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">functional structure </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The line structure is often referred to as a military organization. This is because, like in the military, there is a clear chain of command from top to bottom. Each person reports to one superior and has a set of subordinates reporting to them, if any. This structure is simple and easy to understand.</div>", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE"}, {"id": "objective>Commerce>2009>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The efficiency of an organization is enhanced by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">government assistance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the host community</div>", "<div style=\"font-family:Cambria;font-size:17px;\">customer support </div>", "<div style=\"font-family:Cambria;font-size:17px;\">skilled man power</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Organizational efficiency can be achieved by appropriate utilization of natural and man-made resources, distribution of fine quality product and services as well. Focusing effectively on the employee training and advance education will surely help in attaining the organizational efficiency.</div>", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE"}, {"id": "objective>Commerce>2009>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The concept which focus on consumers in decision-making is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">selling concept</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marketing concept </div>", "<div style=\"font-family:Cambria;font-size:17px;\">product concept </div>", "<div style=\"font-family:Cambria;font-size:17px;\">production concept </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Consumer decision making is viewed as the edifice of the marketing concept, an important orientation in marketing management. The marketing concept is the philosophy that firms should analyze the needs of their customers and then make decisions to satisfy those needs, better than the competition.</div>", "topic": "ELEMENT OF MARKETING : THE MARKETING CONCEPT"}, {"id": "objective>Commerce>2009>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">market skimming is an example of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">market penetration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sales promotion </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pricing policy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">advertising </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">market skimming is a product pricing strategy by which a firm charges the highest initial price that customers will pay. As the demand of the first customers is satisfied, the firm lowers the price to attract another, more price-sensitive segment.</div>", "topic": "ELEMENT OF MARKETING : MARKETING MIX"}, {"id": "objective>Commerce>2009>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important attribute in a sale of goods contract are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">offer and consideration </div>", "<div style=\"font-family:Cambria;font-size:17px;\">price and goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">offer and acceptance </div>", "<div style=\"font-family:Cambria;font-size:17px;\">demand and supply </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most important essential for the enforceability of the Contract of Sale of goods is the price. The price can be termed equivalent to the consideration. In the absence of such price or consideration, the transfer cannot be termed as a sale. The transfer by way of the sale must be in exchange for a price.</div>", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT"}, {"id": "objective>Commerce>2009>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Unresolved dispute between the employer and employees are usually refered to the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">code of product bureau </div>", "<div style=\"font-family:Cambria;font-size:17px;\">personal unit </div>", "<div style=\"font-family:Cambria;font-size:17px;\">disciplinary committee</div>", "<div style=\"font-family:Cambria;font-size:17px;\">industrial arbitration tribunal</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An industrial arbitration tribunal consists of an equal number of representatives of the employers and unions plus a chairperson who, failing agreement on the matter between the parties concerned, is appointed by the Labour Court.</div>", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT OF EMPLOYMENT : DUTIES OF THE EMPLOYEE AND EMPLOYER"}, {"id": "objective>Commerce>2009>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The process of eliminating a virus from a computer program is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">programming</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debugging</div>", "<div style=\"font-family:Cambria;font-size:17px;\">formating</div>", "<div style=\"font-family:Cambria;font-size:17px;\">looping </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In computer programming and software development, debugging is the process of finding and resolving bugs (defects or problems that prevent correct operation) within computer programs, software, or systems.</div>", "topic": "INFORMATIONAND COMMUNICATION TECHNOLOGY (ICT) : PROBLEM"}, {"id": "objective>Commerce>2009>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The primary memory component of a computer is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cache</div>", "<div style=\"font-family:Cambria;font-size:17px;\">console</div>", "<div style=\"font-family:Cambria;font-size:17px;\">assemblers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">compilers</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In computing, a cache is a component that stores data so future requests for that data can be served faster; the data stored in a cache might be the results of an earlier computation, or the duplicates of data stored elsewhere.</div>", "topic": "INFORMATIONAND COMMUNICATION TECHNOLOGY (ICT) : TYPES OF COMPUTER AND FUNCTIONS"}, {"id": "objective>Commerce>2009>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A customer with XYZ PLC sent money through his account to his sister's account in another branch. This is an example of  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">e-business</div>", "<div style=\"font-family:Cambria;font-size:17px;\">e-commerce</div>", "<div style=\"font-family:Cambria;font-size:17px;\">e-finance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">e-banking </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Online banking, also known as internet banking, web banking or home banking, is an electronic payment system that enables customers of a bank or other financial institution to conduct a range of financial transactions through the financial institution's website. </div>", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLEGES"}, {"id": "objective>Commerce>2009>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The economic environment of business is concerned with </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">climate condition </div>", "<div style=\"font-family:Cambria;font-size:17px;\">changing values</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the growth rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the interest rate </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The economic environment refers to all the economic factors that affect commercial and consumer behavior. The economic environment consists of all the external factors in the immediate marketplace and the broader economy. These factors can influence a business, i.e., how it operates and how successful it might become. <br/>  <br/> The growth rate is the rate at which the economy is expanding. It is measured as the percentage change in real gross domestic product (GDP) from one year to the next. <br/>  <br/> The growth rate is an important factor in the economic environment because it affects the demand for goods and services. When the economy is growing, businesses tend to experience higher demand for their products and services. This can lead to increased sales and profits.</div>", "topic": "BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITY : FACTORS"}, {"id": "objective>Commerce>2009>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A firm that disposes its waste properly is discharging its </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">community responsibility </div>", "<div style=\"font-family:Cambria;font-size:17px;\">environmental responsibility </div>", "<div style=\"font-family:Cambria;font-size:17px;\">civic responsibility  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">social responsibility </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Corporate Environmental Responsibility (CER) refers to a company's duties to abstain from damaging natural environments. The term derives from corporate social responsibility (CSR).</div>", "topic": "BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITY : POLLUTION"}];
